#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=105;
ll n,q,m,a[N];
struct node
{
	ll x,y,num[N][N];
	node operator*(const node other)
	{
		node ans;
		ans.x=x,ans.y=other.y;
		for(int i=1;i<=x;i++)
		{
			for(int j=1;j<=other.y;j++)
			{
				ans.num[i][j]=0;
				for(int k=1;k<=y;k++) 
				{
					ans.num[i][j]^=(num[i][k]*other.num[k][j]);
				}
			}
		}
		return ans;
	}
} b[35],ans;
void fun(node x)
{
	cout<<"-------\n";
	cout<<"x : "<<x.x<<"  y : "<<x.y<<"\n";
	for(int i=1;i<=x.x;i++)
	{
		for(int j=1;j<=x.y;j++) cout<<x.num[i][j]<<" ";
		cout<<'\n';
	}
	cout<<"-------\n";
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>q;
	for(int i=1;i<=n;i++) cin>>a[i];
	b[0].x=b[0].y=n;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		b[0].num[u][v]=b[0].num[v][u]=1;
	}
	for(int i=1;i<=31;i++)
	{
		b[i]=b[i-1]*b[i-1];
	}
	while(q--)
	{
		ll num;
		cin>>num;
		ans.x=1;
		ans.y=n;
		for(int i=1;i<=n;i++) ans.num[1][i]=a[i];
		for(int i=31;i>=0;i--)
		{
			if(((ll)1<<i)<=num)
			{
//				cout<<i<<"\n";
//				fun(ans);
//				fun(b[i]);
				ans=ans*b[i];
				num-=((ll)1<<i);
//				fun(ans);
			}
		}
		cout<<ans.num[1][1]<<"\n";
	}
	return 0;
}
